//  IMAGE FETCH & CACHE
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
//  IMAGE FETCH & CACHE (multi-source)
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
const imgCache = {};

async function fetchWikiImage(slug, displayName=''){
  if(imgCache[slug] !== undefined) return imgCache[slug];
  
  let url = null;
  
  // 1) Wikipedia REST (original + thumbnail)
  if (!url) {
    try {
      const res = await fetch(`https://en.wikipedia.org/api/rest_v1/page/summary/${encodeURIComponent(slug)}`, {
        signal: AbortSignal.timeout(5000)
      });
      if(res.ok) {
        const d = await res.json();
        url = d?.originalimage?.source || d?.thumbnail?.source || null;
      }
    } catch(e){}
  }
  
  // 2) MediaWiki pageimages API
  if (!url) {
    try {
      const res = await fetch(
        `https://en.wikipedia.org/w/api.php?action=query&titles=${encodeURIComponent(slug)}&prop=pageimages&format=json&pithumbsize=500&origin=*`,
        { signal: AbortSignal.timeout(6000) }
      );
      if(res.ok) {
        const d = await res.json();
        const pages = d?.query?.pages || {};
        for (const k in pages) {
          const p = pages[k];
          if (p?.original?.source) { url = p.original.source; break; }
          if (p?.thumbnail?.source) { url = p.thumbnail.source; break; }
        }
      }
    } catch(e){}
  }
  
  // 3) Wikimedia Commons (search by title)
  if (!url) {
    try {
      const res = await fetch(
        `https://commons.wikimedia.org/w/api.php?action=query&list=search&srsearch=${encodeURIComponent(slug)}&srnamespace=6&format=json&origin=*`,
        { signal: AbortSignal.timeout(6000) }
      );
      if(res.ok) {
        const d = await res.json();
        const results = d?.query?.search || [];
        if (results.length > 0) {
          // Get first file image info
          const title = results[0].title;
          try {
            const infoRes = await fetch(
              `https://commons.wikimedia.org/w/api.php?action=query&titles=${encodeURIComponent(title)}&prop=imageinfo&iiprop=url&format=json&origin=*`,
              { signal: AbortSignal.timeout(6000) }
            );
            if(infoRes.ok) {
              const info = await infoRes.json();
              const pages2 = info?.query?.pages || {};
              for (const k in pages2) {
                const ii = pages2[k]?.imageinfo || [];
                if (ii.length > 0 && ii[0].url) { url = ii[0].url; break; }
              }
            }
          } catch(e){}
        }
      }
    } catch(e){}
  }
  
  // 4) TMDB (РµСЃР»Рё РµСЃС‚СЊ TMDB ID - С‡РµСЂРµР· РїРѕРёСЃРє РїРѕ РЅР°Р·РІР°РЅРёСЋ)
  if (!url && displayName) {
    try {
      // TMDB search С‚СЂРµР±СѓРµС‚ API key, РёСЃРїРѕР»СЊР·СѓРµРј fallback search
      const cleanName = displayName.replace(/\s+/g, '%20').toLowerCase();
      const res = await fetch(
        `https://api.themoviedb.org/3/search/multi?query=${cleanName}&api_key=6b9761ba22331f04f88db6bf80a87b7e`,
        { signal: AbortSignal.timeout(6000) }
      );
      if(res.ok) {
        const d = await res.json();
        const results = d?.results || [];
        if (results.length > 0 && results[0].poster_path) {
          url = `https://image.tmdb.org/t/p/w500${results[0].poster_path}`;
        }
      }
    } catch(e){}
  }
  
  // 5) Google Custom Search / Fallback (Unsplash + DuckDuckGo proxy)
  if (!url && displayName) {
    try {
      const q = encodeURIComponent(displayName);
      // Try Unsplash first
      const res = await fetch(`https://source.unsplash.com/600x400/?${q}`, {
        method: 'HEAD',
        signal: AbortSignal.timeout(5000)
      });
      if (res.ok) {
        url = `https://source.unsplash.com/600x400/?${q}`;
      }
    } catch(e){}
  }
  
  // 6) Last resort: Emoji placeholder with fallback image
  if (!url && displayName) {
    // Use alternative image source (bing, or direct search service)
    try {
      const q = encodeURIComponent(displayName.split('(')[0].trim());
      url = `https://bing.com/images/search?q=${q}`;
    } catch(e){}
  }
  
  imgCache[slug] = url || ''; // Store even empty string to avoid re-fetching
  return url;
}

// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
//  DYNAMIC INTERFACE UPDATER
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
function updateStaticTexts() {
  const t = TRANSLATIONS[state.lang];
  
  // Header buttons
  document.getElementById('btn-rules').textContent = t.rulesBtn;
  document.getElementById('btn-lang-toggle').textContent = t.langBtn;
  
  // Setup screen
  document.getElementById('setup-label-players').textContent = t.setupPlayers;
  document.getElementById('setup-spy-hint').innerHTML = t.setupSpyHint.replace('{N}', Math.floor(state.playerCount / 3));
  document.getElementById('setup-label-categories').textContent = t.setupCategories;
  
  const allChecked = state.selectedCats.size === CATEGORIES.length;
  document.getElementById('btn-select-all').textContent = allChecked ? t.deselectAll : t.selectAll;
  document.getElementById('btn-start-deal').textContent = t.startBtn;
  
  // Deal screen (Prompts)
  if (document.getElementById('screen-deal').classList.contains('active')) {
    document.getElementById('deal-player-name').textContent = t.playerBadge.replace('{N}', state.currentPlayer + 1);
    const isFirst = state.currentPlayer === 0;
    document.getElementById('deal-prompt-text').textContent = isFirst ? t.promptTake : t.promptPass;
    document.getElementById('btn-open-card-init').textContent = t.openCardBtn;
    document.getElementById('text-tap-open').textContent = t.tapToOpen;
    document.getElementById('btn-restart-action').textContent = t.restartBtn;
    
    if (state.cardOpen) {
      updateOpenedCardContent();
    }
  }
  
  // Final screen
  document.getElementById('final-title').innerHTML = t.finalTitle;
  document.getElementById('label-stat-players').textContent = t.finalPlayers;
  document.getElementById('label-stat-spies').textContent = t.finalSpies;
  document.getElementById('final-description').textContent = t.finalDesc;
  document.getElementById('btn-new-game-restart').textContent = t.newGameBtn;
  
  // Modals
  document.getElementById('confirm-title').textContent = t.abortConfirmTitle;
  document.getElementById('confirm-desc').textContent = t.abortConfirmDesc;
  document.getElementById('btn-cancel').textContent = t.cancelBtn;
  document.getElementById('btn-confirm').textContent = t.confirmBtn;
  
  document.getElementById('modal-rules-title').textContent = t.rulesModalTitle;
  document.getElementById('modal-rules-body').innerHTML = t.rulesContent;
}

function toggleLanguage() {
  state.lang = state.lang === 'ru' ? 'ua' : 'ru';
  updateStaticTexts();
  buildCatsUI(); 
}

// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
//  SETUP SCREEN CONTROLS
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
function buildCatsUI() {
  const container = document.getElementById('cats-container');
  container.innerHTML = '';
  CATEGORIES.forEach(cat => {
    const active = state.selectedCats.has(cat.id);
    const displayName = state.lang === 'ru' ? cat.nameRU : cat.nameUA;
    const el = document.createElement('div');
    el.className = 'cat-toggle' + (active ? ' active' : '');
    el.innerHTML = `
      <div class="ct-icon">${cat.icon}</div>
      <div style="flex: 1;">
        <div class="ct-name">${displayName}</div>
        <div class="ct-count">${cat.chars.length} ${state.lang === 'ru' ? 'РїРµСЂСЃРѕРЅР°Р¶РµР№' : 'РїРµСЂСЃРѕРЅР°Р¶С–РІ'}</div>
      </div>
      <div class="ct-check">${active ? 'вњ“' : ''}</div>
    `;
    el.addEventListener('click', () => toggleCategory(cat.id));
    container.appendChild(el);
  });
}

function toggleCategory(id) {
  if (state.selectedCats.has(id)) {
    if (state.selectedCats.size === 1) {
      showToast(state.lang === 'ru' ? 'Р’С‹Р±РµСЂРё С…РѕС‚СЏ Р±С‹ РѕРґРЅСѓ РєР°С‚РµРіРѕСЂРёСЋ!' : 'РћР±РµСЂРё С…РѕС‡Р° Р± РѕРґРЅСѓ РєР°С‚РµРіРѕСЂС–СЋ!');
      return;
    }
    state.selectedCats.delete(id);
  } else {
    state.selectedCats.add(id);
  }
  buildCatsUI();
  updateStaticTexts();
}

function toggleAll() {
  if (state.selectedCats.size === CATEGORIES.length) {
    state.selectedCats = new Set([CATEGORIES[0].id]);
  } else {
    state.selectedCats = new Set(CATEGORIES.map(c => c.id));
  }
  buildCatsUI();
  updateStaticTexts();
}

function changeCount(delta) {
  const next = state.playerCount + delta;
  if (next < 3 || next > 12) return; 
  state.playerCount = next;
  document.getElementById('player-count').textContent = next;
  updateStaticTexts();
}

// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
//  GAME LOOP IMPLEMENTATION
// в•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђв•ђ
// Secure randomness helpers (uses Web Crypto when available)
function secureRandomInt(max) {
  if (window.crypto && window.crypto.getRandomValues) {
    const range = max;
    const maxUint32 = 0xFFFFFFFF;
    const out = new Uint32Array(1);
    while (true) {
      window.crypto.getRandomValues(out);
      const val = out[0] >>> 0;
      const threshold = Math.floor((maxUint32 + 1) / range) * range;
      if (val < threshold) return val % range;
    }
  }
  return Math.floor(Math.random() * max);
}

function secureShuffle(array) {
  for (let i = array.length - 1; i > 0; i--) {
    const j = secureRandomInt(i + 1);
    [array[i], array[j]] = [array[j], array[i]];
  }
  return array;
}

function startGame() {
  const pool = [];
  CATEGORIES.forEach(cat => {
    if (state.selectedCats.has(cat.id)) {
      pool.push(...cat.chars);
    }
  });
  
  if (pool.length === 0) {
    showToast(TRANSLATIONS[state.lang].noCategoryError);
    return;
  }
  
  const avoidList = new Set(state.usedChars.slice(-Math.ceil(pool.length * 0.3)).map(c => c.wiki));
  const freshList = pool.filter(c => !avoidList.has(c.wiki));
  const finalPool = freshList.length > 0 ? freshList : pool;
  
  const chosen = finalPool[secureRandomInt(finalPool.length)];
  state.chosenChar = chosen;
  state.usedChars.push(chosen);
  if (state.usedChars.length > 30) state.usedChars.shift();
  
  const spiesCount = Math.max(1, Math.floor(state.playerCount / 3));
  const roleIndices = secureShuffle([...Array(state.playerCount).keys()]);
  
  state.spySet = new Set(roleIndices.slice(0, spiesCount));
  state.currentPlayer = 0;
  state.cardOpen = false;
  
  document.getElementById('final-players').textContent = state.playerCount;
  document.getElementById('final-spies').textContent = spiesCount;
  
  showDealPrompt(true);
  switchScreen('screen-deal');
}

function showDealPrompt(isFirst = false) {
  const t = TRANSLATIONS[state.lang];
  document.getElementById('deal-player-name').textContent = t.playerBadge.replace('{N}', state.currentPlayer + 1);
  document.getElementById('deal-prompt-text').textContent = isFirst ? t.promptTake : t.promptPass;
  
  document.getElementById('deal-prompt').style.display = 'block';
  document.getElementById('flip-scene').style.display = 'none';
  document.getElementById('deal-actions').style.display = 'none';
  document.getElementById('flip-card').classList.remove('flipped');
}

function openCard() {
  if (state.cardOpen) return;
  state.cardOpen = true;
  
  updateOpenedCardContent();
  
  document.getElementById('deal-prompt').style.display = 'none';
  document.getElementById('flip-scene').style.display = 'block';
  document.getElementById('deal-actions').style.display = 'none';
  
  requestAnimationFrame(() => {
    requestAnimationFrame(() => {
      document.getElementById('flip-card').classList.add('flipped');
      setTimeout(() => {
        const isLast = state.currentPlayer >= state.playerCount - 1;
        const btnClose = document.getElementById('btn-close-card');
        btnClose.textContent = isLast ? TRANSLATIONS[state.lang].finishHandoutBtn : TRANSLATIONS[state.lang].closeCardBtn;
        document.getElementById('deal-actions').style.display = 'flex';
      }, 400); 
    });
  });
}

function updateOpenedCardContent() {
  const isSpy = state.spySet.has(state.currentPlayer);
  const back = document.getElementById('flip-back');
  const t = TRANSLATIONS[state.lang];
  
  if (isSpy) {
    back.className = 'flip-face flip-back back-spy';
    back.innerHTML = `
      <div class="spy-content">
        <div class="spy-emoji">рџ•µпёЏвЂЌв™‚пёЏ</div>
        <div class="spy-title">${t.youAreSpy}</div>
        <div class="spy-sub">${t.spyTask}</div>
      </div>
      <div class="spy-card-info">
        <div class="spy-badge">
          <div class="spy-dot"></div>
          <div class="spy-badge-text">${t.spyBadge}</div>
        </div>
      </div>
    `;
  } else {
    back.className = 'flip-face flip-back back-char';
    const charName = state.lang === 'ru' ? state.chosenChar.nameRU : state.chosenChar.nameUA;
    back.innerHTML = `
      <div class="card-img-wrap">
        <div class="card-img-placeholder" id="card-ph">${state.chosenChar.emoji}</div>
        <div class="img-loader" id="img-ldr"><div class="spinner"></div></div>
        <img class="card-img loading" id="card-photo" alt="${charName}"/>
        <div class="card-img-overlay"></div>
      </div>
      <div class="card-info">
        <div class="info-trigger-btn" onclick="openInfoModal(event)">i</div>
        <div class="card-top-label">${t.characterYour}</div>
        <div class="card-name">${charName}</div>
        <div class="card-bot-label">${t.characterWarn}</div>
      </div>
    `;
    loadCardImage(state.chosenChar);
  }
}

async function loadCardImage(char) {
  const displayName = state.lang === 'ru' ? char.nameRU : char.nameUA;
  const url = await fetchWikiImage(char.wiki, displayName);
  const imgEl = document.getElementById('card-photo');
  const loader = document.getElementById('img-ldr');
  const ph = document.getElementById('card-ph');
  
  if (!imgEl) return;
  
  if (url) {
    imgEl.onload = () => {
      imgEl.classList.remove('loading');
      if (loader) loader.style.display = 'none';
      if (ph) ph.style.display = 'none';
    };
    imgEl.onerror = () => {
      // On error, try fallback emoji display
      imgEl.style.display = 'none';
      if (ph) ph.style.display = 'flex';
      if (loader) loader.style.display = 'none';
    };
    imgEl.src = url;
  } else {
    // No URL found - show emoji placeholder
    if (loader) loader.style.display = 'none';
    if (ph) ph.style.display = 'flex';
  }
}

function closeCard() {
  document.getElementById('flip-card').classList.remove('flipped');
  document.getElementById('deal-actions').style.display = 'none';
  state.cardOpen = false;
  
  setTimeout(() => {
    document.getElementById('flip-scene').style.display = 'none';
    state.currentPlayer++;
    if (state.currentPlayer >= state.playerCount) {
      switchScreen('screen-final');
    } else {
      showDealPrompt(false);
    }
  }, 450);
}

function confirmAbort() {
  openModal('confirmModal');
}

function executeRestart() {
  closeModal('confirmModal');
  resetGame();
}

function resetGame() {
  state.currentPlayer = 0;
  state.cardOpen = false;

  // Ensure deal-related UI is hidden
  const dealActions = document.getElementById('deal-actions');
  const flipScene = document.getElementById('flip-scene');
  const dealPrompt = document.getElementById('deal-prompt');
  if (dealActions) dealActions.style.display = 'none';
  if (flipScene) flipScene.style.display = 'none';
  if (dealPrompt) dealPrompt.style.display = 'block';

  // Switch back to setup and rebuild setup UI to restore interactions
  switchScreen('screen-setup');
  // Rebuild category elements (restore event listeners) and refresh texts
  buildCatsUI();
  document.getElementById('player-count').textContent = state.playerCount;
  updateStaticTexts();

  // Make sure stepper buttons and any inputs are enabled
  document.querySelectorAll('.stepper button').forEach(b => b.disabled = false);

  // Close any active modals (safety) so they don't block pointer events
  document.querySelectorAll('.modal-overlay.active').forEach(m => m.classList.remove('active'));
}

